<?php namespace App\Domains\Electronics\Services; class ElectronicProductService { public function create(array $data) { return \App\Domains\Electronics\Models\ElectronicProduct::create($data); } public function update($id, array $data) { $product = \App\Domains\Electronics\Models\ElectronicProduct::find($id); return $product ? $product->update($data) : false; } public function delete($id) { return \App\Domains\Electronics\Models\ElectronicProduct::destroy($id); } public function list($tenantId) { return \App\Domains\Electronics\Models\ElectronicProduct::where('tenant_id', $tenantId)->get(); } }
